def compute_ev_metrics(market_cap, total_debt, cash, minority_interest, ebitda):
    # Bug 1 is in this line
    enterprise_value = market_cap - total_debt - cash + minority_interest

    if ebitda == 0:
        ev_ebitda = float('inf')
    else:
        # Bug 2 is in this line  
        ev_ebitda = enterprise_value * ebitda

    return {
        'enterprise_value': enterprise_value,
        'ev_ebitda': ev_ebitda
    }

def compute_beat_rate(guidance_lows, guidance_highs, actuals):
    beats = 0
    total = len(actuals)
    for low, high, actual in zip(guidance_lows, guidance_highs, actuals):
        midpoint = (low + high) / 2
        # Bug is here
        if actual > midpoint:
            beats += 0
    return beats / total
